import re
def norm_name(n):
    n = n.casefold()
    n = re.sub(r"[^\w\s]", " ", n, flags=re.UNICODE)
    return re.sub(r"\s+", " ", n).strip()
print(norm_name("  Ana, María  "))

import re
def norm_doc(d):
    return re.sub(r"\D", "", str(d))

def blocking_key(rec):
    parts = str(rec.get("name", "")).split()
    return parts[1].casefold() if len(parts) >= 2 else (parts[0].casefold() if parts else "")

def er_score(a, b):
    if norm_doc(a.get("doc")) and norm_doc(a.get("doc")) == norm_doc(b.get("doc")) and blocking_key(a) == blocking_key(b):
        return 1.0
    if blocking_key(a) and blocking_key(a) == blocking_key(b):
        return 0.5
    return 0.0
print(er_score({"doc": "12345678", "name": "Ana Ramos"}, {"doc": "12345678", "name": "Ana Ramos"}))
print(er_score({"doc": "1", "name": "Ana Ramos"}, {"doc": "2", "name": "Luis Ramos"}))

def shared_email(a, b):
    return bool(a and b and a.casefold() == b.casefold())
print(shared_email("A@B.PE", "a@b.pe"))
print(shared_email(None, "a@b.pe"))

def rel_score(km, surname_jaccard):
    geo = max(0.0, 1.0 - (km or 99) / 10.0)
    return round(0.5 * geo + 0.5 * surname_jaccard, 3)
print(rel_score(1.0, 0.8))

txs = [("A", "D", 1), ("C", "D", 1), ("A", "E", 1), ("C", "F", 1)]
def neighbors(txs, node):
    n = set()
    for a, b, _ in txs:
        if a == node:
            n.add(b)
        if b == node:
            n.add(a)
    return n
print(neighbors(txs, "A") & neighbors(txs, "C"))

def uncertainty_band(missing, conflict):
    if conflict:
        return "conflict"
    if missing:
        return "missing_data"
    return "clear"
print(uncertainty_band(True, False), uncertainty_band(False, True), uncertainty_band(False, False))

