from math import isfinite

th = {"accept_min": 0.8, "review_low": 0.4}

def decide_ops_status(score, unc, th):
    if score is None or not isfinite(score) or not (0 <= score <= 1):
        return "invalid_input"
    if unc == "high":
        return "needs_review"
    if score < th["review_low"]:
        return "abstain"
    if score < th["accept_min"]:
        return "needs_review"
    return "accept_partial"

for s, u in [(None, "clear"), (0.2, "clear"), (0.5, "clear"), (0.9, "clear"), (0.9, "high")]:
    print(s, u, "→", decide_ops_status(s, u, th))

